local function check_auth(token, allowed_roles)
    local user_role = ngx.re.match(ngx.var.remote_user or "", "^%w+")

    if not user_role then
        ngx.exit(401) -- Unauthorized
    end

    for _, role in ipairs(allowed_roles) do
        if string.find(user_role, role) then
            return true
        end
    end

    ngx.exit(403) -- Forbidden
end

local function skip_permission_check(uri)
    local admin_or_api = ngx.re.match(ngx.var.request_uri, "/admin|/api")
    if admin_or_api then
        return true
    end
end

local auth_token = ngx.req.get_headers()["Authorization"]
if not auth_token then
    ngx.exit(401) -- Unauthorized
end

local allowed_roles = {"admin", "editor"} -- replace with your desired roles
if check_auth(ngx.re.match(auth_token, "Bearer %s+(.+)"), allowed_roles) then
    if not skip_permission_check(ngx.var.request_uri) then
        ngx.exit(403) -- Forbidden
    end
end